var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님, 어디 고장난 데 있으십니까?","JPN":"社長、故障してないでしょうか？","ENG":"Boss, how are your functions?","TWN":"老闆，有哪裡壞掉嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"끄응. 괜찮네. 수납함에 바닷물이 들어간 것만 빼고 말이야.","JPN":"ううむ……問題ない。収納箱に海水が入ったこと以外はな。","ENG":"Ugh, they are fine. Except that my cabinet was flooded with sea water.","TWN":"嗯，還好，只是收納箱浸水了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 그리고 왠지 몸이 아주 개운하군! 마사지라도 받은 기분이야!","JPN":"あ、でもなんだか身体がとてもスッキリするな！　マッサージでも受けた気分だ！","ENG":"Oh, and I feel great! As if I just had a massage!","TWN":"還有，不知道怎麼搞的，身體滿舒坦的！感覺像剛做完按摩一樣！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"로봇도 근육통이 생기나요. 그런 쓸데없는 기능을 잘도 만들어 두셨군요.","JPN":"ロボットも筋肉痛になるんですか？　そんな無駄な機能をよく作りましたね。","ENG":"I didn’t know robots could feel muscular pain. That’s such a useless feature.","TWN":"機器人也會肌肉酸痛嗎？你連那些莫名其妙的功能也有做喔？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어허, 원래 기술의 발전은 쓸데없어 보이는 곳에서부터 시작하는 법일세.","JPN":"ほら、そもそも技術の発展は無駄なところから始まるものさ。","ENG":"You should know that advance comes from useless features.","TWN":"哎唷，技術的發展本來就是從莫名其妙的地方開始的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그보다 그 펭귄들은 어떻게 됐나?","JPN":"それより、ペンギンたちはどうなった？","ENG":"By the way, what happened to the penguins?","TWN":"話說回來，那些企鵝怎麼樣了？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"배달부에게 맡겨 뒀습니다. 지금쯤이면 정리가 다 끝났겠죠.","JPN":"配達員に任せました。今頃片付け終わっているでしょう。","ENG":"The deliverywoman is taking care of them. I’m sure she’s done by now.","TWN":"交給送貨員處理了，現在差不多處理得差不多了吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모~네!","JPN":"モ～ネ！","ENG":"Mo-ne!","TWN":"莫～妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"잠깐만요! 펭귄님들! 아무리 배달에 불만이 있어도 사람을 물에 던지면 안 되죠!","JPN":"待ってください、ペンギン様！　いくら配達に不満があっても人を海に投げ落としてはいけませんよ！","ENG":"Hey, wait! My dear penguins! You should not throw a delivery person to the sea, even if you have a problem with the delivery!","TWN":"等一下！企鵝們！就算要客訴，也不能把人扔進水裡吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗! 잠깐만요, 스톱! 타임!","JPN":"あっ、待って！　ストップ！　ストップ！","ENG":"Oh! Wait! Stop! Time out!","TWN":"哎唷！等一下，停！暫停！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자기가 정리를 당했구만.","JPN":"片付けられたのは本人だったな。","ENG":"I see the deliverywoman has been taken care of.","TWN":"看來是她被企鵝處理。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh*","TWN":"哎…"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저 펭귄들, 우리가 여기 있는 게 마음에 안 들어서 저러는 걸까?","JPN":"あのペンギンたち、私たちがここにいるのが気に食わなくてあんなことをしているのかね。","ENG":"Do you think they are acting like that because they don’t want us here?","TWN":"那些企鵝是因爲不喜歡我們在這裡才那樣嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이유야 아무래도 좋습니다. 휴가를 망치는 방해꾼들이란 사실은 변함없으니까요.","JPN":"理由はどうでもいいです。休みを台無しにする邪魔者という事実は変わりません。","ENG":"Who cares. What’s important is that they are ruining my vacation.","TWN":"理由不管是什麼，都不會改變他們毀掉假期的事實。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"적당히 겁을 줘서 쫓아내겠습니다. 사장님은 잠시 물러나 계세요.","JPN":"適当に脅して追い払います。社長は下がっていてください。","ENG":"I’ll just scare them away. Boss, please stay back.","TWN":"我會稍微教訓一下他們，把他們趕走。老闆請先迴避。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잠깐 기다려 보게. 싸움이 언제나 좋은 해결책인 건…….","JPN":"待ってくれ。戦いが最善の解決策になるとは限らな……","ENG":"Wait. Fighting is not the solution for everything—","TWN":"請稍等一下。不要老是動不動就要動手……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_Q","text":{"KOREA":"앗! 찾았슴다, 펭귄들! 여기 모여 있었슴까!","JPN":"あっ！　見つけた、ペンギン！　ここにいたんっすね！","ENG":"Oh! I found you, penguins! So this is where you’ve been hiding!","TWN":"喔！找到了！企鵝們，原來你們在這裡！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 이 목소리는?","JPN":"おや？　この声は？","ENG":"Hm? This voice...","TWN":"嗯？這個聲音是？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네? 모네!","JPN":"モネ？　モネ！","ENG":"Mone? Mone!","TWN":"莫妮？莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"으으, 기껏 찾았는데 도망가 버렸지 말임다.","JPN":"むむ、せっかく見つけたのに逃げられてしまったっす。","ENG":"Ooh, they all ran away. It was so difficult to find them.","TWN":"呃呃，好不容易才找到的，又被逃掉了！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자네, 정말로 모네 양인가?","JPN":"君、本当にモネか？","ENG":"Are you the real Mone?","TWN":"你，真的是莫妮嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"우왓, 주인님?!","JPN":"わっ、ご主人様！？","ENG":"Whoa! Master?","TWN":"哇！主人？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넵! 진짜 모네임다, 주인님! 여기서 만나다니 무지 기쁘지 말임다!","JPN":"はいっ！　本物のモネっすよ、ご主人様！　ここで会えるなんて、すっごく嬉しいっす！","ENG":"Yes, this is the real Mone, Master! I'm so glad to meet you here, sir!","TWN":"是的！我是真的莫妮，主人！沒想到會在這裡遇到你，超高興的唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"나도 마찬가질세. 못 본 사이에 키도 더 큰 것 같구만.","JPN":"そうだな。見ない間に背が伸びたのではないか？","ENG":"So am I. You look like you’ve grown taller.","TWN":"我也是，一陣子不見，你好像長高了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"헤헤, 사장님도 안 본 사이 더 멋있어지셨지 말임다!","JPN":"ヘヘッ、社長も見ない間にもっとカッコよくなったっす！","ENG":"Heh heh, you look much cooler than before as well, sir!","TWN":"嘿嘿，老闆也變得更帥了唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"눈썰미가 좋군, 모네 양. 최근에 알파트릭스제 최고급 알칼라인 연료 전지를 끼웠거든.","JPN":"よく気づいてくれたな、モネ。この前アルファトリックス製の最高級アルカリ燃料電池に替えたのだ。","ENG":"You have a good eye, Mone. I recently installed Alphatrix's finest alkaline fuel batteries.","TWN":"逃不過你的法眼呢！因為我最近裝了阿爾法崔克斯牌最高級的鹼性燃料電池。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"와하하하하핫!","JPN":"ワッハッハッハッ！","ENG":"Wah hah hah hah!","TWN":"哇哈哈哈哈哈！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"와하하하하하!","JPN":"ワハハハハハハ！","ENG":"Wah hah hah hah!","TWN":"哇哈哈哈哈哈！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"죽이 잘 맞는 사람들끼리 다시 만나서 반가운 건 이해합니다만……","JPN":"気が合う人間同士再会できて嬉しいのは理解しますが……","ENG":"I see you two are having a good time...","TWN":"我明白遇到心智年齡差不多的人很開心…"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"플로라 메이드 서비스는 챔버에 머물고 있지 않았나요? 혼자 여기까지 무슨 일이죠?","JPN":"フローラメイドサービスはチェンバーにいるはずでは？　一人でここまで来たのですか？","ENG":"But I thought the Flora Maid Service was staying in Chamber. What brought you here all by yourself?","TWN":"不過芙蘿拉女僕服務公司不是落腳在強巴嗎？你一個人來這裡有什麼事嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"메이드장님께 휴가를 받았지 말임다. 그래서 아부지랑 엄니 보러 고향에 온 검다.","JPN":"メイド長から休みをもらったっす。それで父ちゃんと母ちゃんに会いにきたっす。","ENG":"The Chief Maid gave me a vacation, ma’am. So I came home to see my parents, ma’am.","TWN":"女僕長放我假唷，所以我才回老家看爸爸媽媽。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부모님을 뵈러……?","JPN":"親御さんに会いに……？","ENG":"To see your parents?","TWN":"回家看爸媽媽…？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"고향에?","JPN":"故郷に？","ENG":"Home?","TWN":"老家？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넵! 저기 있는 커다란 야자수를 끼고 조금만 걸어가면 모네네 마을이 나오지 말임다!","JPN":"はいっ！　あそこにある大きなヤシの木のところを曲がって少し歩けば、モネの村があるっす！","ENG":"Yes, sir and ma’am! Turn at the palm tree over there and you’ll see Mone’s hometown.","TWN":"是的！沿著那邊的巨大椰子樹走，就會看到莫妮住的村莊唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그런데 두 분은 여기 어떻게 오셨슴까? 그라운드 원에 계시던 거 아니었슴까?","JPN":"ところでお二人はなぜここにいるっすか？　グラウンド・ワンにいらっしゃると思ってたっすが。","ENG":"By the way, how did you get here, sir and ma’am? I thought you were in Ground One.","TWN":"不過，你們兩位來到這裡有什麼事情嗎？你們不是待在 G1 嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 그게 말이지…….","JPN":"いや、それが……","ENG":"Oh, that's...","TWN":"啊，那是因為…"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"어푸푸! 저도 떠내려 가요!","JPN":"うぐぐ！　私も流れちゃいます！","ENG":"Hurp! Drifting away over here!","TWN":"啊噗噗！我也快被沖走了啦！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우선 저 사람부터 건져 놓고 얘기하세나!","JPN":"まずはあの人を助けてから話そう！","ENG":"We have to help her first!","TWN":"先把那個人撈上來再說吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"푸하아! 덕분에 살았어요, 사모님!","JPN":"ぷはー！　おかげで助かりました、奥様！","ENG":"Phew! You saved my life, missus!","TWN":"噗哈！謝謝老闆娘救命之恩！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"별말씀을. 그런 능력을 가지고도 당할 거라고 예상 못 한 제 책임이 크니까요.","JPN":"いいえ。そんな能力を持っているのにやられると予想できなかった私の責任もありますから。","ENG":"You’re welcome. I didn’t expect you’d let them get you, even with your ability. That was my fault.","TWN":"不用客氣。都怪我不好，沒預料到擁有那種能力還打不過企鵝。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그리고 앞으로는 부사장님이라고 부르세요.","JPN":"あと、これからは副社長と呼んでください。","ENG":"Also, call me Madame Vice President from now on.","TWN":"另外，之後請稱呼我副總吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"한 번만 더 사모님이라고 부르면 손이 미끄러져서 도로 바다에 빠뜨릴지도 모릅니다.","JPN":"また奥様と呼んできたら、私の手が滑ってまた海に落とすかもしれません。","ENG":"If you call me missus one more time, I might slip and let you fall to the sea again.","TWN":"要是再叫我一次老闆娘，我可能會手滑再把你扔進海裡。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"옴마나? 그새 이혼하셨어요, 사모님?","JPN":"あれれ？　いつの間にか離婚したのですか、奥様？","ENG":"Whaa? Missus, you divorced while I was drowning?","TWN":"我的天啊？老闆娘，你剛才離婚了嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……아직 싱글입니다.","JPN":"……まだ独身です。","ENG":"... I’m single.","TWN":"…我單身。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"으으…… 옷이 쫄딱 젖어 버렸네. 이대로 달리면 감기 걸리겠어요.","JPN":"むむ……服がビショビショに濡れてしまいました。このまま走ると風邪をひいてしまいます。","ENG":"Oh... I’m wet through and through. I’ll get cold if I run in this condition.","TWN":"哎呀…衣服都溼透了，這樣去送貨會感冒的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 휘말리게 해서 미안하군.","JPN":"アハハ、巻き込んですまないな。","ENG":"Hah hah, I’m sorry to get you caught up in this.","TWN":"哈哈。很抱歉牽累你。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"배달은 잠시 쉬고 몸부터 말리게나.","JPN":"配達はしばらく休みにして、服を乾かしてくれ。","ENG":"Take some time off and dry yourself.","TWN":"工作暫停一下，先把身體晾乾吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"옷은 모네한테 주시지 말임다! 빨래 담당으로서 책임지고 깨끗이 세탁해 드리겠슴다!","JPN":"服はモネが預かるっす！　洗濯担当として責任を持ってキレイに洗うっす！","ENG":"Give Mone your clothing, ma’am! I’m in charge of laundry, I will get your clothing cleaned up!","TWN":"衣服交給我吧！身爲洗衣負責人，我會負責洗乾淨！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"옴마야! 펭귄이 커졌다?!","JPN":"わっ！　ペンギンがデカくなった！？","ENG":"Oh my god! The penguin has grown!","TWN":"我的天啊！企鵝長大啦？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모네는 메이드지 펭귄이 아님다!","JPN":"モネはメイドで、ペンギンじゃないっす！","ENG":"Mone is a maid, not a penguin, ma’am!","TWN":"莫妮是女僕，不是企鵝唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이쪽은 아까 그 펭귄이 아니라 플로라 메이드 서비스에서 일하는 모네 양이라네.","JPN":"こちらはさっきのペンギンではなくて、フローラメイドサービスで働くモネだ。","ENG":"This is not the penguin you saw. It’s Mone from the Flora Maid Service.","TWN":"她不是剛剛的企鵝，她是芙蘿拉女僕服務公司的莫妮。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"일전에 우리 회사에서 일도 도와 줬지.","JPN":"以前我が社で仕事を手伝ってくれたんだ。","ENG":"She’s helped our company before.","TWN":"之前有服務過我們公司。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"잘 부탁드림다! 배달부님!","JPN":"よろしくっす！　配達員様！","ENG":"Glad to meet you, delivery lady!","TWN":"請多多指教唷！送貨員！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"플로라 메이드 서비스요? 그럼 베로니카 씨네 직원 분?","JPN":"フローラメイドサービスですか？　じゃあベロニカさんのところのスタッフ？","ENG":"Flora Maid Service? Then you work for Veronica?","TWN":"芙蘿拉女僕服務公司嗎？所以是貝洛妮卡的員工嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"아니, 그치만 펭귄들이랑 똑 닮았잖아요. 쌍둥이나 어릴 때 헤어진 동생처럼.","JPN":"いや、それにしてもペンギンにそっくりすぎでしょう。双子もしくは生き別れた妹みたいに。","ENG":"Well, you look just like the penguins! Like twins, or long-lost siblings!","TWN":"不過你長得也太像企鵝了吧？說不定是雙胞胎，或是從小失散的姊妹。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모네도 그것 때문에 억울해 죽겠슴다!","JPN":"モネもそのせいで悔しいっす！","ENG":"That’s what’s killing me as well, ma’am!","TWN":"我也覺得超煩的！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"휴가를 받아서 아부지랑 엄니 보러 왔는데 마을 어르신들한테 놀림만 받았지 말임다.","JPN":"休みまでもらって父ちゃんと母ちゃんに会いに来たのに、村のみんなにからかわれたっす。","ENG":"I’m only here to see my parents, and the town elders are making fun of me because of these penguins, ma’am.","TWN":"好不容易才有假可以回來看爸爸和媽媽，結果一直被村裡的大人笑。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>아이구! 모네야, 펭귄 탈은 어디다 두고 왔냐?</color>","JPN":"<color=#ffd34c>なあ、モネ！　ペンギンの被り物はどこに置いてきたんだい？</color>","ENG":"<color=#ffd34c>Oh! Mone, where is your penguin costume?</color>","TWN":"<color=#ffd34c>哎唷！ 莫妮，你的企鵝面具呢？</color>"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>동생들은 할아버지 등도 두드려 주고 가던데~</color>","JPN":"<color=#ffd34c>あんたの妹たちはおじさんの肩もトントンしてくれたのになあ。</color>","ENG":"<color=#ffd34c>Your little sisters were kind enough to rub our back.</color>","TWN":"<color=#ffd34c>妹妹們還替爺爺拍背呢~</color>"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그래서 오자마자 어르신들 팔다리만 주물러 드렸지 말임다.","JPN":"それで到着早々村のばっちゃんやじっちゃんたちの肩叩きの仕事に回されたっすよ。","ENG":"So I’ve been giving massages to the town elders since I came home.","TWN":"害我一回來就要替老人家捏手臂！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러면 펭귄들을 찾으러 왔던 이유가……","JPN":"つまりペンギンたちを探していた理由は……","ENG":"So you’re looking for the penguins because...","TWN":"那麼去找企鵝的理由是…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"넵! 모네 대신 할부지 할무니들 안마해 달라고 할 생각이었슴다!","JPN":"はいっ！　モネの代わりにばっちゃんとじっちゃんたちの肩叩きを頼むつもりっす！","ENG":"Yes, sir! I want them to rub down the town elders instead of me!","TWN":"喔！本來是想拜託企鵝，代替我給爺爺奶奶按摩唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"이대로는 종일 안마만 하다 휴가가 끝나 버릴지도 모름다…….","JPN":"このままだと一日中肩叩きばっかりして、休みが終わってしまうっすよ……","ENG":"I can’t spend my vacation giving people massages...","TWN":"因為再這樣下去，我可能整個假期都在按摩…"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그럼 곤란하죠. 휴가는 누구한테도 방해 받지 않고 편안히 지내야 하니까요.","JPN":"それは困りますね。バカンスというものは誰にも邪魔されずリラックスするべきです。","ENG":"That’s not good. No one should be disturbed when they are on vacation.","TWN":"那真的會很困擾呢。因爲所謂的放假，就是要靜靜地度過，不受到任何人的打擾，不是嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"안 그렇습니까, 사장님?","JPN":"そう思いませんか、社長？","ENG":"Don’t you think so, Boss?","TWN":"難道不是嗎，老闆？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠. 흠.","JPN":"コホン、コホン！","ENG":"Ahem, hmm.","TWN":"咳嗯，嗯。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그럼 모네는 이만 펭귄들을 찾으러 가 보겠슴다!","JPN":"ではモネはペンギンを探しにいくっす！","ENG":"Well, Mone will be going to find the penguins now, ma’am!","TWN":"那我要去找企鵝了唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"아 참, 주인님네는 어디서 묵으심까? 모네가 이따 맛있는 야자 열매 갖다 드리겠슴다!","JPN":"あ、ご主人様たちはどこに泊まるっすか？　モネが後で美味しいヤシの実を届けにいきたいっす！","ENG":"Oh, where are you staying, Master? Mone will bring you some delightful coconuts later!","TWN":"對了！主人住在哪裡呢？莫妮等等帶好吃的椰子去給主人唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아직 숙소를 구하지 않았습니다. 갑작스럽게 왔거든요.","JPN":"まだ宿は決めていません。急に来ることになりましたので。","ENG":"We haven’t found accommodations yet.","TWN":"我還沒找到住宿的地方，因為來的有點臨時。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"오? 그러면 모네네 집에서 지내시면 어떠심까?","JPN":"おお！　それじゃ、モネの家に泊まるのはどうっすか？","ENG":"Oh? Then why don’t you stay in Mone’s house, ma’am?","TWN":"喔？那住莫妮家如何呢？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"모네 양네서? 그래도 되겠나?","JPN":"モネの家？　本当にいいのか？","ENG":"In your house? Would that be okay?","TWN":"莫妮的家？這樣可以嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"물론임다. 원래 여름엔 놀러 오시는 분들한테 방도 빌려 주지 말임다.","JPN":"もちろんっす。元々夏になると遊びに来る観光客に部屋を貸していたっす。","ENG":"Of course, sir. We do let out rooms to tourists during the summer.","TWN":"當然可以唷。夏天的時候，我們都會把房間借給來這裡玩的人唷。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"주인님께는 엄니가 맛있는 요리도 만들어 주실 검다!","JPN":"ご主人様には母ちゃんがおいしい料理も振る舞ってくれると思うっすよ！","ENG":"My mama will cook something nice for you too, Master!","TWN":"我媽媽會做好吃的料理給主人吃唷！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오오, 그럼 이 기회에 인사를 드려도 좋겠군.","JPN":"おお、せっかくだしご挨拶しておこう。","ENG":"Oh, I would love to meet your parents.","TWN":"喔喔，那趁機打個招呼也不錯。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부사장, 자네 생각은 어떤가?","JPN":"副社長、君の考えは？","ENG":"Vice President, what do you think?","TWN":"副總，你覺得如何？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"상관없습니다. 처음부터 해변에서 밤을 지새울 생각은 아니었으니까요.","JPN":"構いません。最初から海辺で寝泊まりするつもりはなかったので。","ENG":"Okay. I didn’t plan to stay overnight on the beach, anyways.","TWN":"我無所謂，反正我一開始就沒打算在海邊過夜。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그런데 당신은 왜 그렇게 오두방정입니까?","JPN":"ところであなたはなぜそんなに楽しそうなオーラを出しているんですか？","ENG":"By the way, why are you flapping?","TWN":"不過你是在躁動什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이국적인 요리를 먹어 볼 수 있다고 생각하니 신나서요!","JPN":"異国の料理が食べられると思ったらドキドキが止まりません！","ENG":"I’m so excited to have some exotic food!","TWN":"一想到能吃到異國風料理就很興奮嘛！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"제 영원한 베스트 픽은 칠리 도그지만요! 매콤한 소스를 먹으면 힘이 샘솟거든요!","JPN":"でも私の不動のナンバーワンフードはチリドッグです！　あの甘辛いソースが口の中に広がる瞬間、力がみなぎるんです！","ENG":"Well, my all-time favorite is a chili dog though! The spice brings out the energy!","TWN":"我的最佳選擇永遠是辣味熱狗！ 吃辣的醬汁會充滿力量！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저 촐싹쟁이, 계속 데리고 다니실 건가요?","JPN":"あのお調子者の小娘をいつまで同行させるつもりですか？","ENG":"Are we bringing this frivolous girl with us?","TWN":"老闆打算繼續帶著那個過動兒嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뭘 좀 아는군, 예거 양! 모름지기 여행을 왔으면 식도락을 빼 놓을 수 없지!","JPN":"わかっているな、イェーガーさん。せっかく旅行に来たなら食い道楽は欠かせない！","ENG":"You said it, Ms. Jaegar! Every good vacation needs good food!","TWN":"伊格，你懂！旅行不能少的就是美食！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"……이쪽에도 촐싹쟁이가 있다는 걸 잠시 잊고 있었군요.","JPN":"……うちにもお調子者がいることをしばし忘れていましたね。","ENG":"... Oh, I forgot that you’re just as frivolous as her.","TWN":"…我忘記這裡也有一個過動兒。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야, 기껏 해변까지 와선 이게 뭐야. 수풀 속에 숨어서 훔쳐보기나 하고.","JPN":"ねえ、せっかくビーチに来たのに何なの。茂みの中に隠れて盗み見するなんて。","ENG":"Hey, we came all this way to this beautiful beach, and all we’re doing is peeping through bushes.","TWN":"喂，好不容易來到海邊，這算什麼，只能躲在樹林裡偷看。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"참으세요. 기척을 감추는 것도 메이드가 지켜야 할 몸가짐 중 하나입니다.","JPN":"我慢してください。気配を隠すのもメイドの基本素養の一つです。","ENG":"Please be patient. Hiding oneself is one of the virtues that a maid should retain.","TWN":"忍耐一下。不露聲色也是女僕的功夫之一。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"우리가 여기 온 이유는 모네가 메이드로서 흐트러짐없이 휴가를 보내는지 확인하기 위해서예요.","JPN":"私たちがここに来た理由はモネがメイドとしてのふるまいを乱すことなく休暇を過ごしているかを確認するためです。","ENG":"We’re only here to watch Mone, to see if she’s spending her vacation without tainting the maid’s honor.","TWN":"我們來這裡的目的，是要確認莫妮有沒有乖乖的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"온 지 하루도 안 되서 모네 앞에 나타나는 건 에바참치입니다.","JPN":"到着して1日も経っていないのに姿を表すのはDQNです。","ENG":"It’s been only a day, showing ourselves to Mone would be EXTRA.","TWN":"她回來都還不到一天，我們就出現在她面前，這樣有點Over。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"네 말투가 더 에바참치거든…….","JPN":"あんたの喋り方がDQNだわ……","ENG":"The way you talk is EXTRA...","TWN":"你的語氣才太Over咧…"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그런데 넌 안 궁금해?","JPN":"ところであんたは気にならないの？","ENG":"But aren’t you curious?","TWN":"不過你不好奇嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"말로만 듣던 저 까만 도시락통이 무슨 요술을 부렸길래 메이드장을 홀딱 빠지게 했는지 말이야.","JPN":"あの噂の黒い弁当箱が、どんな手を使ってメイド長をメロメロにさせたのか。","ENG":"What did that Black Lunchbox do to bewitch our Chief Maid?","TWN":"那個傳說中的黑色便當盒到底施了什麼魔法，可以讓女僕長這麼死心踏地？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"따, 딱히 내가 관심 있단 뜻은 아니고, 넌 항상 입만 열면 메이드장 노래를 부르잖아?","JPN":"べ、別に私が興味あるわけじゃなくて、あんたはいつもメイド長のことばかり気にしているでしょ。","ENG":"W-well, that doesn’t mean that I’m interested though. I’m saying this only because you’re always talking about the Chief Maid.","TWN":"我的意思不是我很好奇喔，是因為你開口閉口都是女僕長，我才問你的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"괜찮아요. 제가 조사한 대로라면, 그 의문에 대해서는 조만간 인증각이 뜰 겁니다.","JPN":"大丈夫です。私が調査したとおりなら、その疑問の答えは近いうちに出ると思います。","ENG":"It’s okay. According to my research, the answer to that question will soon be sussed out.","TWN":"沒關係，根據我的調查，這個問題很快就會有答案。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그러니 당분간은 조용히 지켜보기로 하죠.","JPN":"なので、しばらくは静かに様子を見ましょう。","ENG":"So let’s just stay quiet and watch...","TWN":"所以暫時還是靜觀其變吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……저 경망스러운 분이 정말, 메이드장님의 주인님에 어울리시는지.","JPN":"……あんな軽そうな方が、本当にメイド長のご主人様としてふさわしいのかを。","ENG":"... to see if that frivolous man truly deserves to be our Chief Maid’s master.","TWN":"……那個輕佻的人作為女僕長的主人，是否名副其實？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};